import json

threads = [
{"threadId": "14ac0d7408d8030d", "messages": [
{"messageId": "14ac0d7408d8030d", "headers": {"From": "Ankur Yadav <ankurayadav@gmail.com>", "Date": "Tue, 6 Jan 2015 11:58:37 -0800", "Subject": "[opencog-dev] GSOC project - ROS proxy for OpenCog"}, "body": "I am a Computer Engineering student. I want to work on the ROS proxy for OpenCog for GSoC 2015."},
{"messageId": "14ac1798705a14d6", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Tue, 6 Jan 2015 16:59:14 -0600", "Subject": "Re: [opencog-dev] GSOC project - ROS proxy for OpenCog"}, "body": "Three places where this can be done: replacing the current protocol used to drive Unity game engine characters with ROS, getting ROS to communicate between OpenPsi and eva_behavior, and improving the current robots code for various robots. The first two can be done without physical robots."},
{"messageId": "14ac1d30311303c2", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Tue, 6 Jan 2015 19:37:18 -0500", "Subject": "Re: [opencog-dev] GSOC project - ROS proxy for OpenCog"}, "body": "Replacing Unity networking would be suitable for someone who likes game AI. Making OpenCog control specific robots using Gazebo simulations would also be a meaningful project."},
{"messageId": "14ac1e2841fa3a97", "headers": {"From": "Morgan Creekmore <morgan.creekmore@gmail.com>", "Date": "Tue, 6 Jan 2015 17:51:39 -0700", "Subject": "Re: [opencog-dev] GSOC project - ROS proxy for OpenCog"}, "body": "I am currently working on updating spock to work with the newest Minecraft version. I am hoping to write a plugin for spock that uses ROS to communicate with OpenCog."},
{"messageId": "14ac1f54bd3899a3", "headers": {"From": "Cosmo Harrigan <cosmo.harrigan@singularityu.org>", "Date": "Tue, 6 Jan 2015 17:14:44 -0800", "Subject": "Re: [opencog-dev] GSOC project - ROS proxy for OpenCog"}, "body": "Excellent! Have you already seen this thesis from Jonas Kemper, who implemented a Spock interface to Minecraft for another AGI project MicroPsi?"},
{"messageId": "14b9dce9813ef32a", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Wed, 18 Feb 2015 11:47:43 -0600", "Subject": "Re: [opencog-dev] Re: GSOC project - ROS proxy for OpenCog"}, "body": "The github.com/opencog/ros consists entirely of docker files for running robots and Hanson Robotics heads, using blender for simulations not gazebo. Currently opencog has extremely poor 3D awareness, capability or dexterity. It does not know how to enter a room, look around, figure out where walls and doors are. It cannot recognize a table, roll up to it, and pick up an object. For this you need gazebo, not a game engine."},
{"messageId": "14b9fca62d5adb64", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Thu, 19 Feb 2015 11:03:33 +0800", "Subject": "Re: [opencog-dev] Re: GSOC project - ROS proxy for OpenCog"}, "body": "The ros_opencog_robot_embodiment repo was created when Jamie and Shujing were starting work on using the planner to control a Turtlebot robot. This work was left off partway through. OpenCog can represent 3D environments using the 3DSpaceMap. I have suggested replacing its guts with an OctoMap."},
{"messageId": "14ba53110c5261ff", "headers": {"From": "Jamie Diprose <jamie.diprose@gmail.com>", "Date": "Fri, 20 Feb 2015 11:39:40 +1300", "Subject": "Re: [opencog-dev] Re: GSOC project - ROS proxy for OpenCog"}, "body": "I personally think OpenCog internal messaging system should be fixed before work on embodiment is done. That is what hindered me from finishing that project. Its not very transparent how to communicate with the embodiment module and its all done with ugly XML."},
{"messageId": "14ba532494b2a75f", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Fri, 20 Feb 2015 12:15:08 +0800", "Subject": "Re: [opencog-dev] Re: GSOC project - ROS proxy for OpenCog"}, "body": "We plan to have Hana work on replacing the current messaging system with something ROS-based. She will be in HK from mid/late March thru the end of June with this as one of her goals."}
]}
]

for t in threads:
    with open("raw_data_exports/gmail_raw_2015/" + t["threadId"] + ".json", "w") as f:
        json.dump(t, f, indent=2)
    print("Saved " + t["threadId"])
